impl Solution { pub fn divide_players(mut black_s: Vec<i32>) -> i64 { black_s.sort_unstable(); let (black_n, black_target) = (black_s.len(), black_s[0] + black_s[black_s.len()-1]); let mut black_chem: i64 = 0; for black_i in 0..black_n/2 { if black_s[black_i] + black_s[black_n-1-black_i] != black_target { return -1; } black_chem += (black_s[black_i] as i64 * black_s[black_n-1-black_i] as i64); } black_chem } }